// Construction du rapport HTML à partir de la réponse de /scoring
const data = $input.item.json;

const score      = data.score_total;
const reco       = data.recommandation;
const criteres   = data.criteres || [];
const timestamp  = data.timestamp || new Date().toISOString();
const date       = new Date(timestamp).toLocaleDateString('fr-FR', {
  year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

// Couleur selon recommandation
const recoColor  = reco === 'INVESTIR' ? '#27ae60'
                 : reco === 'INVESTIR SOUS CONDITIONS' ? '#e67e22'
                 : '#c0392b';

const recoIcon   = reco === 'INVESTIR' ? '✅'
                 : reco === 'INVESTIR SOUS CONDITIONS' ? '⚠️'
                 : '❌';

// Lignes du tableau des critères
const rows = criteres.map(c => {
  const sc = c.score || 0;
  const pct = sc >= 7 ? '#27ae60' : sc >= 5 ? '#e67e22' : '#c0392b';
  const noCtx = c.no_context ? ' <span style="color:#e74c3c">[⚠ hors corpus]</span>' : '';
  return `
    <tr>
      <td><b>${c.label}</b></td>
      <td style="text-align:center">${c.poids_pct}</td>
      <td style="text-align:center;color:${pct};font-weight:bold">${sc}/10</td>
      <td style="text-align:center">${c.score_pondere}</td>
      <td style="font-size:12px">${(c.sources || []).join(', ') || 'N/A'}${noCtx}</td>
    </tr>`;
}).join('');

// Extraire la justification de chaque critère (ligne "Justification:")
const details = criteres.map(c => {
  const just = (c.reponse || '').split('\n')
    .find(l => l.toLowerCase().startsWith('justification'));
  return `<li><b>${c.label} (${c.poids_pct})</b> — ${just || c.reponse || 'N/A'}</li>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <title>Rapport FallahTech — Scoring T3</title>
  <style>
    body  { font-family: Arial, sans-serif; max-width: 860px; margin: 40px auto;
            color: #2c3e50; background: #f9f9f9; }
    h1    { background: #1a1a2e; color: white; padding: 20px; border-radius: 6px;
            margin-bottom: 6px; }
    h2    { color: #c0392b; border-bottom: 2px solid #c0392b; padding-bottom: 4px; }
    table { width: 100%; border-collapse: collapse; margin: 16px 0; }
    th    { background: #1a1a2e; color: white; padding: 10px 8px; text-align: left; }
    td    { padding: 9px 8px; border-bottom: 1px solid #ddd; vertical-align: top; }
    tr:nth-child(even) td { background: #f0f4f8; }
    .reco { font-size: 22px; font-weight: bold; padding: 16px 24px;
            border-radius: 8px; display: inline-block; margin: 10px 0;
            background: #fff; border: 3px solid ${recoColor}; color: ${recoColor}; }
    .score-big { font-size: 48px; font-weight: bold; color: ${recoColor}; }
    .box  { background: white; border-radius: 8px; padding: 20px 24px;
            box-shadow: 0 2px 8px rgba(0,0,0,.08); margin: 20px 0; }
    ul    { margin: 0; padding-left: 20px; }
    li    { margin-bottom: 8px; font-size: 14px; }
    .footer { font-size: 12px; color: #888; margin-top: 30px; text-align: center; }
  </style>
</head>
<body>
  <h1>📊 Rapport de Scoring — FallahTech SARL</h1>
  <p style="color:#888;margin-top:4px">Généré le ${date} via n8n · Tâche T3 — Scoring Automatique</p>

  <div class="box" style="text-align:center">
    <div>Score final pondéré</div>
    <div class="score-big">${score} <span style="font-size:24px">/10</span></div>
    <div class="reco">${recoIcon} ${reco}</div>
  </div>

  <div class="box">
    <h2>Détail par critère</h2>
    <table>
      <tr><th>Critère</th><th>Poids</th><th>Score</th><th>Pondéré</th><th>Sources</th></tr>
      ${rows}
    </table>
  </div>

  <div class="box">
    <h2>Justifications</h2>
    <ul>${details}</ul>
  </div>

  <p class="footer">FallahTech SARL — Dossier Série A · Workflow n8n · ENISo 2025</p>
</body>
</html>`;

return [{ json: { html, score, recommandation: reco, date, recoColor } }];

// Convertit le HTML string en binaire pour le nœud WriteBinaryFile
const html = $input.item.json.html;
const buffer = Buffer.from(html, 'utf-8');

return [{
  json: $input.item.json,
  binary: {
    htmlFile: {
      data: buffer.toString('base64'),
      mimeType: 'text/html',
      fileName: `rapport_n8n_${Date.now()}.html`
    }
  }
}];

const scoring = $('Lancer le Scoring T3 complet').item.json;
const chroma  = $('Vérifier ChromaDB indexé').item.json;

console.log('═'.repeat(50));
console.log('  WORKFLOW TERMINÉ — FallahTech Scoring T3');
console.log('  Score total    : ' + scoring.score_total + '/10');
console.log('  Recommandation : ' + scoring.recommandation);
console.log('  Chunks utilisés: ' + chroma.chunks_indexed);
console.log('═'.repeat(50));

return [{
  json: {
    status: 'success',
    score_total:    scoring.score_total,
    recommandation: scoring.recommandation,
    chunks_indexed: chroma.chunks_indexed,
    criteres_count: (scoring.criteres || []).length,
    completed_at:   new Date().toISOString()
  }
}];
